// LESSON: Collection Interface API - Reference Page 2.
// You will learn: Use Collection add/remove/contains, iteration, and array conversion.
import java.util.ArrayList;
import java.util.Collection;
import java.util.Iterator;

class CollectionInterfaceReference {
  public static void main(String[] args) {
    example1Queries();
    example2Updates();
    example3Iteration();
  }

  static void example1Queries() {
    Collection<String> names = new ArrayList<>();
    names.add("Ada");
    names.add("Bo");
    int count = names.size();
    boolean empty = names.isEmpty();
    boolean hasAda = names.contains("Ada");
    System.out.println(count + " " + empty + " " + hasAda);
  }

  static void example2Updates() {
    Collection<String> tasks = new ArrayList<>();
    boolean added = tasks.add("compile");
    boolean removed = tasks.remove("compile");
    tasks.add("test");
    tasks.clear();
    System.out.println(added + " " + removed + " " + tasks.size());
  }

  static void example3Iteration() {
    Collection<String> tasks = new ArrayList<>();
    tasks.add("todo-read");
    tasks.add("done-test");
    tasks.add("todo-submit");
    for (String task : tasks) {
      System.out.println(task);
    }
    Iterator<String> iterator = tasks.iterator();
    while (iterator.hasNext()) {
      String task = iterator.next();
      if (task.startsWith("done")) {
        iterator.remove();
      }
    }
    String[] copied = tasks.toArray(new String[0]);
    System.out.println(copied.length);
  }
}
